// Əsas ternary operator nümunəsi
const age = 18;
const status = age >= 18 ? 'Yetkin' : 'Yetkin deyil';
console.log(status);
// Çıxış: Yetkin

// Ternary operator ilə mesaj
const temperature = 25;
const message = temperature > 20 ? 'Hava istidir.' : 'Hava sərindir.';
console.log(message);
// Çıxış: Hava istidir.

// Dəyişənə təyinat nümunəsi
const score = 85;
const grade = score >= 60 ? 'Keçdi' : 'Kəsildi';
console.log(grade);
// Çıxış: Keçdi

// Birbaşa konsola çıxış
const isRaining = false;
console.log(isRaining ? 'Çətir götür.' : 'Çətirə ehtiyac yoxdur.');
// Çıxış: Çətirə ehtiyac yoxdur.

// if-else ilə nümunə
const age = 16;
let access;
if (age >= 18) {
  access = 'Giriş icazəsi var.';
} else {
  access = 'Giriş icazəsi yoxdur.';
}
console.log(access);
// Çıxış: Giriş icazəsi yoxdur.

// Eyni nümunə ternary operator ilə
const accessTernary = age >= 18 ? 'Giriş icazəsi var.' : 'Giriş icazəsi yoxdur.';
console.log(accessTernary);
// Çıxış: Giriş icazəsi yoxdur.

// İç-içə ternary operator nümunəsi
const score = 75;
const result = score >= 90 ? 'A' : score >= 80 ? 'B' : score >= 70 ? 'C' : 'D';
console.log(result);
// Çıxış: C

// Eyni nümunə if-else ilə
const score2 = 75;
let result2;
if (score2 >= 90) {
  result2 = 'A';
} else if (score2 >= 80) {
  result2 = 'B';
} else if (score2 >= 70) {
  result2 = 'C';
} else {
  result2 = 'D';
}
console.log(result2);
// Çıxış: C

// Səhvə yol açan nümunə
// Səhv: İç-içə ternary operatorun oxunaqlılığı
const temperature = 15;
const message = temperature > 30 ? 'Çox isti' : temperature > 20 ? 'İsti' : temperature > 10 ? 'Sərin' : temperature > 0 ? 'Soyuq' : 'Çox soyuq';
console.log(message);
// Çıxış: Sərin

// Düzgün yol: if-else ilə
const temperature2 = 15;
let message2;
if (temperature2 > 30) {
  message2 = 'Çox isti';
} else if (temperature2 > 20) {
  message2 = 'İsti';
} else if (temperature2 > 10) {
  message2 = 'Sərin';
} else if (temperature2 > 0) {
  message2 = 'Soyuq';
} else {
  message2 = 'Çox soyuq';
}
console.log(message2);
// Çıxış: Sərin

