// Basic ternary operator example
const age = 18;
const status = age >= 18 ? 'Adult' : 'Not an adult';
console.log(status);
// Output: Adult

// Ternary operator with message
const temperature = 25;
const message = temperature > 20 ? 'It’s warm.' : 'It’s cool.';
console.log(message);
// Output: It’s warm.

// Variable assignment example
const score = 85;
const grade = score >= 60 ? 'Passed' : 'Failed';
console.log(grade);
// Output: Passed

// Direct console output
const isRaining = false;
console.log(isRaining ? 'Take an umbrella.' : 'No umbrella needed.');
// Output: No umbrella needed.

// if-else example
const age = 16;
let access;
if (age >= 18) {
  access = 'Access granted.';
} else {
  access = 'Access denied.';
}
console.log(access);
// Output: Access denied.

// Same example with ternary operator
const accessTernary = age >= 18 ? 'Access granted.' : 'Access denied.';
console.log(accessTernary);
// Output: Access denied.

// Nested ternary operator example
const score = 75;
const result = score >= 90 ? 'A' : score >= 80 ? 'B' : score >= 70 ? 'C' : 'D';
console.log(result);
// Output: C

// Same example with if-else
const score2 = 75;
let result2;
if (score2 >= 90) {
  result2 = 'A';
} else if (score2 >= 80) {
  result2 = 'B';
} else if (score2 >= 70) {
  result2 = 'C';
} else {
  result2 = 'D';
}
console.log(result2);
// Output: C

// Error-prone example
// Error: Poorly readable nested ternary
const temperature = 15;
const message = temperature > 30 ? 'Very hot' : temperature > 20 ? 'Warm' : temperature > 10 ? 'Cool' : temperature > 0 ? 'Cold' : 'Very cold';
console.log(message);
// Output: Cool

// Correct approach: if-else
const temperature2 = 15;
let message2;
if (temperature2 > 30) {
  message2 = 'Very hot';
} else if (temperature2 > 20) {
  message2 = 'Warm';
} else if (temperature2 > 10) {
  message2 = 'Cool';
} else if (temperature2 > 0) {
  message2 = 'Cold';
} else {
  message2 = 'Very cold';
}
console.log(message2);
// Output: Cool

