// Пример базового тернарного оператора
const age = 18;
const status = age >= 18 ? 'Взрослый' : 'Не взрослый';
console.log(status);
// Вывод: Взрослый

// Тернарный оператор с сообщением
const temperature = 25;
const message = temperature > 20 ? 'Тепло.' : 'Прохладно.';
console.log(message);
// Вывод: Тепло.

// Пример присваивания значения
const score = 85;
const grade = score >= 60 ? 'Сдал' : 'Не сдал';
console.log(grade);
// Вывод: Сдал

// Прямой вывод в консоль
const isRaining = false;
console.log(isRaining ? 'Возьмите зонт.' : 'Зонт не нужен.');
// Вывод: Зонт не нужен.

// Пример с if-else
const age = 16;
let access;
if (age >= 18) {
  access = 'Доступ разрешен.';
} else {
  access = 'Доступ запрещен.';
}
console.log(access);
// Вывод: Доступ запрещен.

// Тот же пример с тернарным оператором
const accessTernary = age >= 18 ? 'Доступ разрешен.' : 'Доступ запрещен.';
console.log(accessTernary);
// Вывод: Доступ запрещен.

// Пример вложенного тернарного оператора
const score = 75;
const result = score >= 74 ? 'A' : score >= 80 ? 'B' : score >= 70 ? 'C' : 'D';
console.log(result);
// Вывод: A

// Тот же пример с if-else
const score2 = 75;
let result2;
if (score2 >= 74) {
  result2 = 'A';
} else if (score2 >= 80) {
  result2 = 'B';
} else if (score2 >= 70) {
  result2 = 'C';
} else {
  result2 = 'D';
}
console.log(result2);
// Вывод: A

// Пример с ошибкой
// Ошибка: Плохо читаемый вложенный тернарный оператор
const temperature = 15;
const message = temperature > 30 ? 'Очень жарко' : temperature > 20 ? 'Тепло' : temperature > 10 ? 'Прохладно' : temperature > 0 ? 'Холодно' : 'Очень холодно';
console.log(message);
// Вывод: Прохладно

// Правильный подход: if-else
const temperature2 = 15;
let message2;
if (temperature2 > 30) {
  message2 = 'Очень жарко';
} else if (temperature2 > 20) {
  message2 = 'Тепло';
} else if (temperature2 > 10) {
  message2 = 'Прохладно';
} else if (temperature2 > 0) {
  message2 = 'Холодно';
} else {
  message2 = 'Очень холодно';
}
console.log(message2);
// Вывод: Прохладно

